#!/usr/bin/env bash
# apply-v0.3.1.sh — diagram/timeline/steps/contrast/feature-showcase のzod検証化
#                    ＋ eslint parser向けoverride撤去
# 前提: apply-v0.3.0.sh 適用済み（zod依存・src/schema/{primitives,chart,issues}.ts が存在）
# 冪等（1回目=OK・2回目=SKIP）。実行後に typecheck / vitest / eslint まで通す。
#
# 方針: 今回は5type・7関数にまたがる変更のため、アンカー単位のstr.replaceではなく
# 「検証済みファイル全体」をbase64で埋め込み、マーカー文字列の有無で冪等性を判定する方式にした。
# （v0.3.0でのアンカー転記ミス実績を踏まえた安全策）
set -euo pipefail
cd "$(dirname "$0")/.."

MARKER='// v0.3.1-zod-applied'

# ---------------------------------------------------------------------------
# 0. 前提チェック
# ---------------------------------------------------------------------------
if ! grep -q '"zod"' package.json; then
  echo '[ERROR] zod が package.json にありません。先に apply-v0.3.0.sh を適用してください'
  exit 1
fi
if [ ! -f src/schema/primitives.ts ]; then
  echo '[ERROR] src/schema/primitives.ts がありません。先に apply-v0.3.0.sh を適用してください'
  exit 1
fi

# ---------------------------------------------------------------------------
# 1. src/schema/*.ts を新規作成（chart.ts は上書き＝comparison-chart系の型強化を含む）
# ---------------------------------------------------------------------------
mkdir -p src/schema
if [ -f "src/schema/diagram.ts" ]; then
  status_skip="src/schema/diagram.ts already exists"
  echo "[SKIP] $status_skip"
else
  echo "" | base64 -d > "src/schema/diagram.ts"
  echo "[OK] src/schema/diagram.ts created"
fi
if [ -f "src/schema/timeline.ts" ]; then
  status_skip="src/schema/timeline.ts already exists"
  echo "[SKIP] $status_skip"
else
  echo "" | base64 -d > "src/schema/timeline.ts"
  echo "[OK] src/schema/timeline.ts created"
fi
if [ -f "src/schema/steps.ts" ]; then
  status_skip="src/schema/steps.ts already exists"
  echo "[SKIP] $status_skip"
else
  echo "" | base64 -d > "src/schema/steps.ts"
  echo "[OK] src/schema/steps.ts created"
fi
if [ -f "src/schema/contrast.ts" ]; then
  status_skip="src/schema/contrast.ts already exists"
  echo "[SKIP] $status_skip"
else
  echo "" | base64 -d > "src/schema/contrast.ts"
  echo "[OK] src/schema/contrast.ts created"
fi
if [ -f "src/schema/feature.ts" ]; then
  status_skip="src/schema/feature.ts already exists"
  echo "[SKIP] $status_skip"
else
  echo "" | base64 -d > "src/schema/feature.ts"
  echo "[OK] src/schema/feature.ts created"
fi

# chart.ts はv0.3.0で作成済みだが、comparison-chart系の型強化（labels/center/leftのcoerce.string化・
# zComparisonLeftStat追加）を含むため、v0.3.1版で上書きする。マーカーで冪等判定。
if grep -q 'zComparisonLeftStat' src/schema/chart.ts 2>/dev/null; then
  echo "[SKIP] src/schema/chart.ts already v0.3.1"
else
  echo "" | base64 -d > "src/schema/chart.ts"
  echo "[OK] src/schema/chart.ts updated (v0.3.1: comparison-chart型強化)"
fi

# ---------------------------------------------------------------------------
# 2. src/parser/slideMarkdown.ts を全置換
# ---------------------------------------------------------------------------
if grep -q "$MARKER" src/parser/slideMarkdown.ts 2>/dev/null; then
  echo "[SKIP] slideMarkdown.ts: already patched (v0.3.1)"
else
  cp src/parser/slideMarkdown.ts "/tmp/slideMarkdown.ts.pre-v0.3.1.bak"
  echo "" | base64 -d > src/parser/slideMarkdown.ts
  if ! grep -q "$MARKER" src/parser/slideMarkdown.ts; then
    echo "[ERROR] slideMarkdown.ts: マーカー埋め込みに失敗しました。/tmp/slideMarkdown.ts.pre-v0.3.1.bak から復元してください"
    exit 1
  fi
  echo "[OK] slideMarkdown.ts patched (diagram/timeline/steps/contrast/feature-showcaseをzod化)"
fi

# ---------------------------------------------------------------------------
# 3. eslint.config.js から parser向けoverrideを撤去
# ---------------------------------------------------------------------------
if grep -q "no-base-to-string" eslint.config.js 2>/dev/null; then
  cp eslint.config.js "/tmp/eslint.config.js.pre-v0.3.1.bak"
  echo "" | base64 -d > eslint.config.js
  echo "[OK] eslint.config.js: parser向けoverride撤去"
else
  echo "[SKIP] eslint.config.js: override already removed"
fi

# ---------------------------------------------------------------------------
# 4. 検証
# ---------------------------------------------------------------------------
echo '--- verify (grep) ---'
test -f src/schema/diagram.ts && echo '[OK] src/schema/diagram.ts exists'
test -f src/schema/timeline.ts && echo '[OK] src/schema/timeline.ts exists'
test -f src/schema/steps.ts && echo '[OK] src/schema/steps.ts exists'
test -f src/schema/contrast.ts && echo '[OK] src/schema/contrast.ts exists'
test -f src/schema/feature.ts && echo '[OK] src/schema/feature.ts exists'
grep -q "$MARKER" src/parser/slideMarkdown.ts && echo '[OK] slideMarkdown.ts patch marker present'
grep -q "no-base-to-string" eslint.config.js && echo '[ERROR] eslint override still present' && exit 1
echo '[OK] eslint override removed'

echo '--- typecheck ---'
npx tsc -b --noEmit

echo '--- vitest ---'
npx vitest run

echo '--- eslint（overrideなし・recommendedTypeCheckedフル適用）---'
npx eslint src

echo '--- prettier（今回変更ファイルのみ）---'
npx prettier --check src/schema/*.ts src/parser/slideMarkdown.ts eslint.config.js

echo '=== apply-v0.3.1.sh completed ==='
